#include <stdio.h>
#include <string.h>

void computePrefix(char* pattern, int m, int* lps) {
    int length = 0;
    lps[0] = 0; // lps[0] is always 0

    int i = 1;
    while (i < m) {
        if (pattern[i] == pattern[length]) {
            length++;
            lps[i] = length;
            i++;
        } else {
            if (length != 0) {
                length = lps[length - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }
}

int Search(char* text, char* pattern) {
    int n = strlen(text);
    int m = strlen(pattern);
    if (m == 0) return 0; // edge case: empty pattern

    int* lps = (int*)malloc(sizeof(int) * m);
    computePrefix(pattern, m, lps);

    int i = 0; // index for text
    int j = 0; // index for pattern

    while (i < n) {
        if (text[i] == pattern[j]) {
            i++;
            j++;
        }
        if (j == m) {
            free(lps);
            return i - j; // match found
        } else if (i < n && text[i] != pattern[j]) {
            if (j != 0) {
                j = lps[j - 1];
            } else {
                i++;
            }
        }
    }

    free(lps);
    return -1; // no match
}

int main() {
    char text[100001], pattern[100001];
    scanf("%s", text);
    scanf("%s", pattern);
    printf("%d\n", Search(text, pattern));
    return 0;
}

